{
  "worker_id": 6,
  "phase": "01e",
  "items": [
    {
      "source_file": "outputs/01b_PARTIAL_W4B5_1770279190.json",
      "status": "success",
      "trust_model": {
        "actors": [
          {
            "id": "actor-blob-submitter",
            "name": "Blob Submitter (External Data Provider)",
            "description": "Any entity that submits blob data to the system for encoding into polynomial commitments and cells. The blob is raw bytes of exactly BYTES_PER_BLOB length. This is the outermost data origin and the system's primary untrusted input surface. Blob content determines all downstream polynomial evaluations, KZG proofs, and data columns."
          },
          {
            "id": "actor-kzg-trusted-setup",
            "name": "KZG Trusted Setup (KZG_SETUP_G1_MONOMIAL / KZG_SETUP_G2_MONOMIAL)",
            "description": "The cryptographic trusted setup ceremony that produced the structured reference string (SRS) used in KZG_SETUP_G1_MONOMIAL and KZG_SETUP_G2_MONOMIAL. This is a foundational trust anchor: all KZG proof generation (SG-014 compute_kzg_proof_multi_impl) and batch verification (SG-015 verify_cell_kzg_proof_batch_impl) depend on these parameters being honestly generated. If the toxic waste from the ceremony was not destroyed, the entire commitment scheme is broken."
          },
          {
            "id": "actor-polynomial-engine",
            "name": "Polynomial Arithmetic Engine",
            "description": "The internal computational module implementing polynomial operations over BLS12-381 scalar fields: FFT (SG-003, SG-004), coset FFT (SG-005), polynomial addition (SG-008), multiplication (SG-009), division (SG-010), interpolation (SG-011), vanishing polynomial construction (SG-012), and Horner evaluation (SG-013). This engine is trusted as a correct implementation of finite field arithmetic."
          },
          {
            "id": "actor-cell-encoder",
            "name": "Cell Encoder / Decoder",
            "description": "The component responsible for serializing and deserializing field elements to/from cell byte representations (SG-001 cell_to_coset_evals, SG-002 coset_evals_to_cell). It bridges the byte-level blob representation and the algebraic field element domain. Encoding/decoding correctness is critical: any error here corrupts all downstream polynomial operations."
          },
          {
            "id": "actor-proof-generator",
            "name": "KZG Proof Generator",
            "description": "The component that generates KZG multi-opening proofs for cells (SG-014 compute_kzg_proof_multi_impl, SG-019 compute_cells_and_kzg_proofs_polynomialcoeff, SG-020 compute_cells_and_kzg_proofs). It computes quotient polynomials and commits them using the trusted setup. The proof generator must produce proofs that are verifiable by any honest verifier."
          },
          {
            "id": "actor-batch-verifier",
            "name": "Batch KZG Proof Verifier",
            "description": "The component that performs batched verification of multiple cell KZG proofs in a single pairing check (SG-015 verify_cell_kzg_proof_batch_impl, SG-021 verify_cell_kzg_proof_batch). It uses the Fiat-Shamir heuristic (SG-006) to derive a random challenge for aggregation. This is the primary cryptographic gatekeeper: it determines whether cells and proofs are accepted as valid."
          },
          {
            "id": "actor-recovery-engine",
            "name": "Data Recovery Engine (Reed-Solomon Erasure Coding)",
            "description": "The component that recovers the original polynomial from a subset of cells using Reed-Solomon erasure coding techniques (SG-023 recover_polynomialcoeff, SG-024 recover_cells_and_kzg_proofs). It requires at least 50% of cells (CELLS_PER_EXT_BLOB / 2) to be available. Recovery correctness is essential for data availability guarantees."
          },
          {
            "id": "actor-fiat-shamir-oracle",
            "name": "Fiat-Shamir Random Oracle (Hash Function)",
            "description": "The hash function (hash_to_bls_field) used to derive the random challenge r for batch verification via the Fiat-Shamir heuristic (SG-006 compute_verify_cell_kzg_proof_batch_challenge). This transforms the interactive proof protocol into a non-interactive one. The hash function is assumed to behave as a random oracle."
          },
          {
            "id": "actor-validator-node",
            "name": "Validator Node (Honest Validator)",
            "description": "A consensus-layer validator that computes cells from blobs (SG-002 cells_and_kzg_proofs_construction), constructs data column sidecars (SG-003 get_data_column_sidecars), publishes sidecars to gossip subnets (SG-006 sidecar_publishing), and retains sidecars for the required epochs (SG-007 sidecar_retention). Validators have custody requirements proportional to their stake (SG-001 get_validators_custody_requirement)."
          },
          {
            "id": "actor-beacon-state",
            "name": "Beacon State (Consensus State)",
            "description": "The beacon chain state that provides validator effective balances for custody requirement computation (SG-001), block headers for sidecar construction (SG-004), and KZG commitments for data integrity verification. The state is assumed to be the canonical finalized or justified state."
          },
          {
            "id": "actor-gossip-network",
            "name": "Gossip Network (Data Column Subnets)",
            "description": "The GossipSub network layer over which data column sidecars are published (SG-006 sidecar_publishing). Each sidecar is published to a deterministic subnet based on column_index. The network is an untrusted transport: messages may be dropped, duplicated, reordered, or injected by adversaries."
          },
          {
            "id": "actor-data-requester",
            "name": "Data Requester (Peer / Light Client)",
            "description": "Any entity requesting data column sidecars from a validator during the retention period (SG-007 sidecar_retention). The validator MUST serve sidecars when requested during the retention period. The requester is untrusted and may attempt to exhaust the validator's resources."
          },
          {
            "id": "actor-external-user",
            "name": "External User / Transaction Sender",
            "description": "An external entity (EOA) that initiates transactions, including legacy, EIP-1559 (FeeMarket), blob (EIP-4844), access-list, and set-code (EIP-7702) transactions containing Authorization tuples. They originate the data that eventually gets encoded, hashed, and stored on-chain. Users interact with the deposit contract to make beacon chain deposits. The sender is identified via ECDSA signature recovery (recover_sender). Users are untrusted and all inputs they provide (gas, fees, nonce, calldata, blob data, authorization lists) must be validated."
          },
          {
            "id": "actor-deposit-contract",
            "name": "Deposit Contract",
            "description": "The canonical beacon chain deposit contract at address 0x00000000219ab540356cbb839cbe05303d7705fa. It emits DepositEvent logs that the execution layer parses to construct deposit requests for the consensus layer. Its address and event signature hash are hardcoded constants."
          },
          {
            "id": "actor-execution-client",
            "name": "Execution Layer Client",
            "description": "The execution layer node software that processes blocks, executes transactions, maintains state tries, encodes accounts via RLP (encode_account), parses transaction receipts, extracts deposit data (extract_deposit_data, parse_deposit_requests), computes requests hashes (compute_requests_hash), encodes and decodes receipts (encode_receipt, decode_receipt), constructs bloom filters (add_to_bloom, logs_bloom), manages block/header/receipt/log/withdrawal data structures, and orchestrates the complete state transition pipeline. This is the system under specification for the Osaka fork."
          },
          {
            "id": "actor-consensus-layer",
            "name": "Consensus Layer (Beacon Chain)",
            "description": "The Ethereum consensus layer that provides the parent_beacon_block_root, withdrawal instructions, and drives the fork-choice rule. It communicates with the execution layer via the Engine API. Withdrawals originate from the consensus layer and are processed unconditionally (no balance check, no gas cost). The consensus layer is trusted to provide correct beacon roots and valid withdrawal instructions. It also consumes requests_hash and deposit requests produced by the execution layer."
          },
          {
            "id": "actor-block-builder",
            "name": "Block Builder / Proposer (Validator)",
            "description": "The entity responsible for constructing and proposing blocks containing a header, ordered transactions, withdrawals, and ommers. In post-merge Ethereum, this is a proof-of-stake validator. The proposer sets the coinbase address and receives priority fees. Controls transaction inclusion and ordering within a block, which directly determines deposit request ordering. The proposer is semi-trusted: it can order transactions but cannot forge invalid state transitions because the execution layer re-validates everything."
          },
          {
            "id": "actor-state-trie",
            "name": "State / Receipts Trie",
            "description": "The Merkle Patricia Trie data structures (state trie for accounts, receipts trie for transaction receipts, transactions trie, withdrawals trie). These are trusted internal data structures that provide integrity guarantees via cryptographic roots. State roots computed after block application must match the block header's state_root."
          },
          {
            "id": "actor-authorizer",
            "name": "EIP-7702 Authorizer",
            "description": "An account holder who signs an Authorization tuple (chain_id, address, nonce, y_parity, r, s) to delegate code execution to another address via EIP-7702 set-code transactions. This is a distinct role from the transaction sender."
          },
          {
            "id": "actor-rlp-codec",
            "name": "RLP Codec Library (ethereum_rlp)",
            "description": "The ethereum_rlp library responsible for serializing and deserializing data structures including Receipt, Header, Block, and Account objects. Both encode_receipt and decode_receipt depend on this library for correct round-trip encoding. Bugs could cause consensus splits across clients."
          },
          {
            "id": "actor-keccak",
            "name": "Keccak-256 Hash Function",
            "description": "The cryptographic hash primitive used in bloom filter construction (add_to_bloom), account code hashing (encode_account), parent hash verification (validate_header), block hash computation (get_last_256_block_hashes), state root computation, and transaction signing. Correctness, collision-resistance, and preimage-resistance of keccak256 are assumed."
          },
          {
            "id": "actor-smart-contract",
            "name": "Smart Contract (Log Emitter)",
            "description": "Deployed contract code that emits Log events (address, topics, data) during EVM execution. Logs are consumed by the bloom filter (logs_bloom) and receipt construction pipelines. The log address must match the executing contract, and topics are bounded by LOG0-LOG4 opcodes."
          },
          {
            "id": "actor-p2p-peer",
            "name": "P2P Network Peer",
            "description": "A remote execution-layer node that transmits encoded blocks, headers, receipts, and transactions over the devp2p wire protocol. Data from peers crosses a network trust boundary and must be decoded and validated before acceptance."
          },
          {
            "id": "actor-system-address",
            "name": "System Address (0xfffffffffffffffffffffffffffffffffffffffe)",
            "description": "A privileged pseudo-actor used as the origin/caller for system transactions. System transactions interact with pre-deployed system contracts (beacon roots, history storage, withdrawal requests, consolidation requests) with a fixed gas allowance of 30,000,000. No value is transferred and should_transfer_value is False. This address cannot be spoofed by user transactions because it is reserved."
          },
          {
            "id": "actor-system-contracts",
            "name": "System Contracts (Pre-deployed)",
            "description": "A set of pre-deployed smart contracts at well-known addresses that perform protocol-level functions: BEACON_ROOTS_ADDRESS (stores beacon block roots), HISTORY_STORAGE_ADDRESS (stores block hashes), WITHDRAWAL_REQUEST_ADDRESS (processes validator withdrawal requests), and CONSOLIDATION_REQUEST_ADDRESS (processes validator consolidation requests). For checked system transactions, the protocol verifies code existence and successful execution. For unchecked system transactions, no such verification occurs."
          },
          {
            "id": "actor-evm",
            "name": "EVM (Execution Engine)",
            "description": "The Ethereum Virtual Machine that processes message calls. It executes transaction code, manages gas accounting, handles state modifications, and produces outputs including logs, gas refunds, and accounts to delete. The EVM is the trusted computing base of the execution layer."
          },
          {
            "id": "actor-parent-block",
            "name": "Parent Block (Chain History)",
            "description": "The immediately preceding block in the canonical chain. It provides the parent header used for validation (parent hash, timestamp ordering, block number sequencing, base fee calculation, excess blob gas calculation). The parent block is trusted because it has already been validated and accepted into the chain. Chain retains at most 255 blocks (get_last_256_block_hashes)."
          },
          {
            "id": "actor-transaction-validator",
            "name": "Transaction Validation Pipeline",
            "description": "The ordered sequence of validation checks that a transaction must pass before execution. This includes type checking, contract creation restrictions, fee validation, gas limit checks, init_code size limits, blob-specific validation, authorization list checks, nonce matching, balance sufficiency, and sender code validation. Each check raises a specific InvalidTransaction subclass on failure. The validation dispatch follows a general-to-specific ordering (exceptions.py SG-004)."
          }
        ],
        "trust_boundaries": [
          {
            "id": "tb-001",
            "from_actor": "actor-blob-submitter",
            "to_actor": "actor-cell-encoder",
            "description": "Raw blob bytes cross into the cryptographic domain when cell_to_coset_evals (SG-001) converts byte segments into BLS field elements via bytes_to_bls_field. Malformed or adversarial blob data could encode values outside the valid field range. The assertion len(blob) == BYTES_PER_BLOB (SG-018 INV-001, SG-020 INV-002) is the first validation gate."
          },
          {
            "id": "tb-002",
            "from_actor": "actor-cell-encoder",
            "to_actor": "actor-polynomial-engine",
            "description": "Deserialized field elements from cells are passed to the polynomial engine for FFT, interpolation, and evaluation. The polynomial engine trusts that input field elements are valid members of the BLS12-381 scalar field. If bytes_to_bls_field produces invalid field elements, all polynomial operations produce incorrect results."
          },
          {
            "id": "tb-003",
            "from_actor": "actor-polynomial-engine",
            "to_actor": "actor-proof-generator",
            "description": "Polynomial coefficients produced by polynomial_eval_to_coeff (SG-007) are consumed by compute_kzg_proof_multi_impl (SG-014) to generate KZG proofs. The proof generator trusts the polynomial engine to produce correct coefficient representations. An incorrect inverse FFT or bit-reversal permutation would produce invalid proofs that fail verification."
          },
          {
            "id": "tb-004",
            "from_actor": "actor-kzg-trusted-setup",
            "to_actor": "actor-proof-generator",
            "description": "The proof generator uses KZG_SETUP_G1_MONOMIAL from the trusted setup to compute g1_lincomb (SG-014, q_commit). The entire security of the KZG commitment scheme rests on the trusted setup being honestly generated. This is a static, ceremony-level trust boundary that cannot be verified at runtime."
          },
          {
            "id": "tb-005",
            "from_actor": "actor-kzg-trusted-setup",
            "to_actor": "actor-batch-verifier",
            "description": "The batch verifier uses both KZG_SETUP_G1_MONOMIAL[:n] and KZG_SETUP_G2_MONOMIAL[n] from the trusted setup in the pairing check (SG-015). If the structured reference string is compromised, an adversary can forge proofs that pass batch verification for arbitrary data."
          },
          {
            "id": "tb-006",
            "from_actor": "actor-fiat-shamir-oracle",
            "to_actor": "actor-batch-verifier",
            "description": "The batch verifier derives the random challenge r from the hash function via compute_verify_cell_kzg_proof_batch_challenge (SG-006). The challenge r must be unpredictable before all inputs are committed. The Fiat-Shamir heuristic security requires the hash function to behave as a random oracle and that all verifier-relevant data is included in the hash input (SG-006 INV-001)."
          },
          {
            "id": "tb-007",
            "from_actor": "actor-blob-submitter",
            "to_actor": "actor-batch-verifier",
            "description": "When externally supplied cells, commitments, and proofs are presented for batch verification (SG-021 verify_cell_kzg_proof_batch), all inputs cross from the untrusted external domain into the verifier. The verifier performs exhaustive input validation: length checks (INV-002), commitment byte length (BYTES_PER_COMMITMENT), cell index bounds (INV-004), cell byte length (BYTES_PER_CELL), and proof byte length (BYTES_PER_PROOF)."
          },
          {
            "id": "tb-008",
            "from_actor": "actor-data-requester",
            "to_actor": "actor-recovery-engine",
            "description": "Partial cell sets provided for recovery (SG-024 recover_cells_and_kzg_proofs) cross into the recovery engine. The recovery engine validates: matching lengths (INV-001), at least 50% cell availability (INV-002), no duplicate indices (INV-003), sorted indices (INV-003), valid index bounds (INV-004), and correct cell byte lengths. A malicious requester could provide inconsistent cells that lead to recovery of an incorrect polynomial."
          },
          {
            "id": "tb-009",
            "from_actor": "actor-recovery-engine",
            "to_actor": "actor-proof-generator",
            "description": "The recovered polynomial from recover_polynomialcoeff (SG-023) is passed to compute_cells_and_kzg_proofs_polynomialcoeff (SG-019) to regenerate all cells and proofs. If the recovery engine produces an incorrect polynomial (e.g., due to adversarial cell inputs or insufficient cell count), all regenerated proofs will be invalid."
          },
          {
            "id": "tb-010",
            "from_actor": "actor-validator-node",
            "to_actor": "actor-gossip-network",
            "description": "Validators publish data column sidecars to gossip subnets (SG-006 sidecar_publishing). Each sidecar is deterministically routed to subnet compute_subnet_for_data_column_sidecar(column_index). The validator trusts the network to propagate sidecars, but the network may drop, censor, or delay them. Publishing to the wrong subnet would prevent peers from receiving the data."
          },
          {
            "id": "tb-011",
            "from_actor": "actor-beacon-state",
            "to_actor": "actor-validator-node",
            "description": "The beacon state provides validator effective balances used to compute custody requirements (SG-001 get_validators_custody_requirement). Custody is proportional to stake: total_node_balance // BALANCE_PER_ADDITIONAL_CUSTODY_GROUP, clamped to [VALIDATOR_CUSTODY_REQUIREMENT, NUMBER_OF_CUSTODY_GROUPS]. The validator trusts the state to be canonical. A stale or forked state would produce incorrect custody assignments."
          },
          {
            "id": "tb-012",
            "from_actor": "actor-data-requester",
            "to_actor": "actor-validator-node",
            "description": "During the retention period (MIN_EPOCHS_FOR_DATA_COLUMN_SIDECARS_REQUESTS), validators MUST serve sidecars on request (SG-007). Requesters are untrusted: they may flood the validator with requests (DoS), request data outside the retention window, or attempt to extract custody group membership information."
          },
          {
            "id": "tb-013",
            "from_actor": "actor-validator-node",
            "to_actor": "actor-cell-encoder",
            "description": "During sidecar construction (SG-002 cells_and_kzg_proofs_construction), the validator uses compute_cells to decompose blobs into cells and pairs them with proofs from blobs_bundle.proofs. The validator trusts that blobs_bundle.proofs are correctly aligned with cells: proofs[start:end] for each blob (INV-003). Misaligned proof slicing would produce sidecars with invalid cell-proof pairings."
          },
          {
            "id": "tb-014",
            "from_actor": "actor-validator-node",
            "to_actor": "actor-proof-generator",
            "description": "get_data_column_sidecars_from_block (SG-004) extracts KZG commitments and computes a Merkle inclusion proof from the signed block. The block is trusted (already validated), but the Merkle proof computation is a cryptographic operation that must correctly target the blob_kzg_commitments field in the block body tree."
          },
          {
            "id": "tb-015",
            "from_actor": "actor-external-user",
            "to_actor": "actor-execution-client",
            "description": "External user submits transaction data (including account data and EIP-7702 Authorization tuples) to the execution client. The execution client must validate all inputs before processing. This is the primary untrusted input boundary for the execution layer. All transaction fields (type, gas, fees, nonce, value, data, blob hashes, authorization list) must be validated before execution. The transaction passes through validate_transaction, check_transaction (fork.py SG-006), and multiple exception-class guards (exceptions.py SG-004) before reaching the EVM."
          },
          {
            "id": "tb-016",
            "from_actor": "actor-deposit-contract",
            "to_actor": "actor-execution-client",
            "description": "The deposit contract emits DepositEvent logs that the execution client must parse. The execution client trusts the log data format but validates all offsets and sizes rigorously via extract_deposit_data. The contract address (DEPOSIT_CONTRACT_ADDRESS) and event signature hash (DEPOSIT_EVENT_SIGNATURE_HASH) serve as the authentication mechanism."
          },
          {
            "id": "tb-017",
            "from_actor": "actor-execution-client",
            "to_actor": "actor-consensus-layer",
            "description": "The execution client produces deposit_requests bytes and a requests_hash (via compute_requests_hash using SHA-256) that the consensus layer consumes. The consensus layer trusts the execution client to have faithfully extracted and ordered all deposit data from transaction receipts."
          },
          {
            "id": "tb-018",
            "from_actor": "actor-block-builder",
            "to_actor": "actor-execution-client",
            "description": "The block builder provides the BlockOutput containing receipt_keys ordering and the receipts_trie. The execution client trusts receipt_keys ordering to determine deposit request ordering, and trusts that trie_get returns valid receipt data for each key. The block header and body are validated through state_transition (fork.py SG-003) and validate_header (fork.py SG-005). The proposer's header claims (gas_used, state_root, transaction_root, receipt_root, bloom, withdrawals_root, blob_gas_used, requests_hash) are independently recomputed and verified. Block RLP size is bounded by MAX_RLP_BLOCK_SIZE."
          },
          {
            "id": "tb-019",
            "from_actor": "actor-authorizer",
            "to_actor": "actor-execution-client",
            "description": "An EIP-7702 authorizer signs an Authorization tuple with ECDSA (y_parity, r, s) delegating code to a target address. The execution client must verify the signature, chain_id for replay protection, and nonce for freshness before accepting the authorization."
          },
          {
            "id": "tb-020",
            "from_actor": "actor-state-trie",
            "to_actor": "actor-execution-client",
            "description": "The execution client reads from and writes to the state and receipts tries. Account encoding (encode_account) produces RLP data stored in the state trie. The storage_root parameter is a 32-byte Merkle root that must be externally supplied and correct. State modifications follow a strict sequence: fee deduction before execution, nonce increment before message call, gas refund capped and floored, miner receives only priority fee, destroyed accounts cleaned up."
          },
          {
            "id": "tb-021",
            "from_actor": "actor-external-user",
            "to_actor": "actor-deposit-contract",
            "description": "External users interact with the deposit contract to make beacon chain deposits. The contract emits logs that later get parsed by the execution client. The user trusts the contract to correctly emit deposit events with proper BLS public keys, withdrawal credentials, amounts, signatures, and indices."
          },
          {
            "id": "tb-022",
            "from_actor": "actor-external-user",
            "to_actor": "actor-execution-client",
            "description": "Transaction submission boundary for blocks.py. Raw transactions from EOAs enter the execution engine for validation and inclusion. The transaction carries a type discriminator (Legacy/AccessList/FeeMarket/Blob/SetCode) and a cryptographic signature (v/r/s or y_parity). The execution engine must validate the transaction type, decode it correctly, and recover the sender via ECDSA before trusting any field."
          },
          {
            "id": "tb-023",
            "from_actor": "actor-block-builder",
            "to_actor": "actor-execution-client",
            "description": "Block construction boundary. The proposer supplies a Block containing a Header (21 fields), a list of transactions (typed or legacy), ommers (always empty post-merge), and withdrawals. The execution engine must validate every header field against consensus rules, verify transaction ordering, and ensure the proposer has not manipulated coinbase, timestamp, or extra_data."
          },
          {
            "id": "tb-024",
            "from_actor": "actor-consensus-layer",
            "to_actor": "actor-execution-client",
            "description": "Consensus-to-execution layer boundary for withdrawals and beacon data. The beacon chain supplies Withdrawal objects (index, validator_index, address, amount), parent_beacon_block_root, and requests_hash (EIP-7685). The execution layer trusts these values as authoritative but must validate their format and consistency with header commitments. Beacon roots are stored via unchecked system transactions (no error validation). Withdrawals directly increase account balances without gas costs or sender balance checks."
          },
          {
            "id": "tb-025",
            "from_actor": "actor-smart-contract",
            "to_actor": "actor-execution-client",
            "description": "Log emission boundary. Smart contracts emit Log events (address, topics, data) during EVM execution. These logs are consumed by logs_bloom for bloom filter construction and by receipt_construction for inclusion in Receipt objects. The execution engine must ensure the log address matches the executing contract and that topics do not exceed the LOG4 limit (4 topics max). Deposit requests are extracted from block output logs (not from system transactions)."
          },
          {
            "id": "tb-026",
            "from_actor": "actor-p2p-peer",
            "to_actor": "actor-execution-client",
            "description": "Network deserialization boundary for receipts. Encoded receipts (with type-prefix bytes 0x01-0x04 or raw RLP for legacy) arrive from peers and are decoded via decode_receipt. The assert statement in decode_receipt (receipt[0] in {1,2,3,4}) is a critical gatekeeper. Malformed or adversarial payloads could exploit the RLP decoder."
          },
          {
            "id": "tb-027",
            "from_actor": "actor-execution-client",
            "to_actor": "actor-rlp-codec",
            "description": "Serialization library boundary. The execution engine delegates encoding and decoding of Receipt, Header, Block, and other data structures to the RLP codec. Bugs in the RLP library could produce malformed encodings or fail to reject invalid inputs, causing consensus splits between clients using different RLP implementations."
          },
          {
            "id": "tb-028",
            "from_actor": "actor-execution-client",
            "to_actor": "actor-keccak",
            "description": "Cryptographic primitive boundary for bloom filter. The bloom filter's add_to_bloom function depends on keccak256 to derive 3 bit positions per entry. A weak or incorrect hash implementation would undermine the bloom filter's probabilistic guarantees and could cause false negatives in log search."
          },
          {
            "id": "tb-029",
            "from_actor": "actor-execution-client",
            "to_actor": "actor-p2p-peer",
            "description": "Receipt encoding output boundary. The execution engine serializes receipts via encode_receipt (type-prefix + RLP) for transmission to peers. If the encoding is inconsistent with the canonical specification, receiving peers will reject the data, causing network partitions."
          },
          {
            "id": "tb-030",
            "from_actor": "actor-system-address",
            "to_actor": "actor-system-contracts",
            "description": "System address invoking pre-deployed system contracts during block body application (fork.py SG-011 apply_body). Two variants exist: checked (fork.py SG-009 process_checked_system_transaction) requires the target to have code and the call to succeed (raises InvalidBlock on failure), while unchecked (fork.py SG-010 process_unchecked_system_transaction) performs no validation on code existence or execution result. System transactions use a fixed gas of 30,000,000 and transfer no value. Execution order: beacon roots -> history storage -> user transactions -> withdrawals -> requests."
          },
          {
            "id": "tb-031",
            "from_actor": "actor-parent-block",
            "to_actor": "actor-execution-client",
            "description": "Parent block data used for header validation and base fee calculation. The parent block provides: parent_hash (verified via keccak256 in validate_header, fork.py SG-005), parent_gas_used and parent_gas_limit (for base fee calculation via calculate_base_fee_per_gas, fork.py SG-004), parent timestamp (for ordering), parent excess_blob_gas, and the last 255 block hashes (get_last_256_block_hashes, fork.py SG-002). The parent is trusted because it was previously validated."
          },
          {
            "id": "tb-032",
            "from_actor": "actor-external-user",
            "to_actor": "actor-transaction-validator",
